+        this.log('info', 'Claude Code not found - AI workers will run in local fallback mode');
+      }
+    } catch (error) {
+      this.log('warn', `Failed to initialize headless executor: ${error}`);
+      this.headlessAvailable = false;
+    }
+  }
+
+  /**
